import fs from 'node:fs';
import { parseDocument, parse as parseYaml, Scalar } from 'yaml';
export function readYamlFile(file) {
    const content = fs.readFileSync(file, 'utf-8');
    return parseYaml(content);
}
export function editYamlFile(file, callback) {
    const content = fs.readFileSync(file, 'utf-8');
    const doc = parseDocument(content);
    callback(doc);
    // prefer single quotes
    fs.writeFileSync(file, doc.toString({ singleQuote: true }), 'utf-8');
}
export function scalarString(value) {
    return new Scalar(value);
}
